import sys
input = sys.stdin.readline

def main():
    q = int(input())
    parent = list(range(500001))

    def find(x):
        while parent[x] != x:
            parent[x] = parent[parent[x]]
            x = parent[x]
        return x

    arr = []
    for _ in range(q):
        line = input().split()
        if line[0] == '1':
            arr.append(int(line[1]))
        else:
            x, y = int(line[1]), int(line[2])
            fx = find(x)
            if fx == x:
                parent[x] = find(y)

    print(*[find(v) for v in arr])

